// pillarOption allows management of the mutation configuration using functional options.
type pillarOption func(*PillarMutation)

// newPillarMutation creates new mutation for the Pillar entity.
func newPillarMutation(c config, op Op, opts ...pillarOption) *PillarMutation {
	m := &PillarMutation{
		config:        c,
		op:            op,
		typ:           TypePillar,
		clearedFields: make(map[string]struct{}),
	}
	for _, opt := range opts {
		opt(m)
	}
	return m
}

// withPillarID sets the ID field of the mutation.
func withPillarID(id uuid.UUID) pillarOption {
	return func(m *PillarMutation) {
		var (
			err   error
			once  sync.Once
			value *Pillar
		)
		m.oldValue = func(ctx context.Context) (*Pillar, error) {
			once.Do(func() {
				if m.done {
					err = errors.New("querying old values post mutation is not allowed")
				} else {
					value, err = m.Client().Pillar.Get(ctx, id)
				}
			})
			return value, err
		}
		m.id = &id
	}
}

// withPillar sets the old Pillar of the mutation.
func withPillar(node *Pillar) pillarOption {
	return func(m *PillarMutation) {
		m.oldValue = func(context.Context) (*Pillar, error) {
			return node, nil
		}
		m.id = &node.ID
	}
}

// Client returns a new `ent.Client` from the mutation. If the mutation was
// executed in a transaction (ent.Tx), a transactional client is returned.
func (m PillarMutation) Client() *Client {
	client := &Client{config: m.config}
	client.init()
	return client
}

// Tx returns an `ent.Tx` for mutations that were executed in transactions;
// it returns an error otherwise.
func (m PillarMutation) Tx() (*Tx, error) {
	if _, ok := m.driver.(*txDriver); !ok {
		return nil, errors.New("internal: mutation is not running in a transaction")
	}
	tx := &Tx{config: m.config}
	tx.init()
	return tx, nil
}

